import{_ as t,o as r,c as a,ak as i}from"./chunks/framework.D-xjpKOc.js";const h=JSON.parse('{"title":"Shimera - Brief Technique","description":"","frontmatter":{},"headers":[],"relativePath":"fr/devdoc/technical_brief.md","filePath":"fr/devdoc/technical_brief.md"}'),n={name:"fr/devdoc/technical_brief.md"};function s(o,e,l,d,c,u){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="shimera-brief-technique" tabindex="-1">Shimera - Brief Technique <a class="header-anchor" href="#shimera-brief-technique" aria-label="Permalink to “Shimera - Brief Technique”">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h2><p>Ce document propose un aperçu concis de Shimera à destination des partenaires, recruteurs et lecteurs externes. Pour le détail technique, voir les pages de documentation liées.</p><h2 id="apercu-du-projet" tabindex="-1">Aperçu du projet <a class="header-anchor" href="#apercu-du-projet" aria-label="Permalink to “Aperçu du projet”">​</a></h2><p>Shimera est une librairie C++ qui unifie l&#39;intégration d&#39;effets visuels (shaders) à travers plusieurs backends de rendu (OpenGL natif, SFML et Raylib) derrière une API unique et cohérente.</p><p>Le projet est développé par une équipe de trois personnes et se trouve actuellement en <strong>cour de développement</strong> (C++23, compilé avec Xmake), avec les backends OpenGL, SFML et Raylib déjà implémentés.</p><h2 id="architecture-principale" tabindex="-1">Architecture principale <a class="header-anchor" href="#architecture-principale" aria-label="Permalink to “Architecture principale”">​</a></h2><p>Shimera est construit comme une abstraction en couches au-dessus d&#39;OpenGL :</p><ol><li><strong>API publique</strong> : un point d&#39;entrée compact (<code>shimera.h</code>) avec gestion des exports statiques/dynamiques.</li><li><strong>Abstraction de backend</strong> : <code>IBackend</code> et <code>BackendFactory</code> définissent les contrats de création pour les framebuffers, textures, shaders et post-processeurs ; le backend concret est sélectionné à la <strong>compilation</strong> via une macro préprocesseur, et non par chargement de plugin à l&#39;exécution.</li><li><strong>Backends concrets</strong> : OpenGL, SFML et Raylib implémentent chacun la capture de scène via leur mécanisme natif (FBO, <code>RenderTexture</code>, <code>RenderTexture2D</code>), tandis que l&#39;exécution du post-processing reste pilotée par OpenGL dans tous les cas.</li><li><strong>Framework d&#39;effets</strong> : une API fluide basée sur le CRTP (<code>ShaderEffect&lt;Derived&gt;</code>) permet de déclarer et chaîner les effets (framebuffers en ping-pong).</li></ol><p>Détail complet : <a href="./architecture/technical_architecture.html">Documentation de l&#39;architecture</a></p><h2 id="innovation-technique" tabindex="-1">Innovation technique <a class="header-anchor" href="#innovation-technique" aria-label="Permalink to “Innovation technique”">​</a></h2><ul><li><strong>Compatible avec plusieurs backends</strong> : la plupart des librairies de shaders ne fonctionnent qu&#39;avec un seul backend. Shimera traite SFML, Raylib et OpenGL comme différentes variantes d&#39;un même pipeline GL, et masque cette différence à l&#39;utilisateur.</li><li><strong>Chaînage d&#39;effets multiples</strong> : un pipeline à plusieurs effets, qui demande normalement des heures de gestion manuelle des framebuffers et du binding de textures, se réduit à quelques appels de méthode, tout en gardant l&#39;accès aux uniforms bas niveau quand nécessaire.</li></ul><p>Détail complet : <a href="./../userdoc/why_shimera.html">Pourquoi Shimera</a></p><h2 id="performances-demontrees" tabindex="-1">Performances démontrées <a class="header-anchor" href="#performances-demontrees" aria-label="Permalink to “Performances démontrées”">​</a></h2><p>Mesures sur 5 000 frames par effet (100 frames de chauffe), sur un runner GitHub Actions self-hosted dédié (Quadro RTX 5000) :</p><table tabindex="0"><thead><tr><th>Backend</th><th>FPS moyen (sans effet)</th><th>FPS moyen (effet simple typique)</th></tr></thead><tbody><tr><td>OpenGL natif</td><td>25 510 fps</td><td>22 000 fps</td></tr><tr><td>Raylib</td><td>5 257 fps</td><td>5 000 – 5 400 fps</td></tr><tr><td>SFML</td><td>5 012 fps</td><td>4 400 – 5 000 fps</td></tr></tbody></table><p>Détail complet : <a href="./../userdoc/performance/benchmark.html">Documentation des performances</a></p><h2 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to “Roadmap”">​</a></h2><p><strong>Juillet 2026</strong> : actuellement, Shimera possède une couche d&#39;abstraction distincte pour chaque backend (OpenGL, SFML, Raylib). L&#39;équipe teste si celle-ci peut être remplacée par une architecture générique unique, valable pour n&#39;importe quel backend. Le résultat détermine la direction prise par le projet pour la suite du cycle de développement :</p><ul><li><strong>Plan A (si l&#39;architecture générique fonctionne) :</strong><ul><li>Août : refactorisation de la librairie sur une branche dédiée autour de la nouvelle architecture générique.</li><li>Septembre : intégration de <a href="https://shader-slang.org/" target="_blank" rel="noreferrer">Slang</a> dans le workflow et migration des shaders GLSL existants vers Slang.</li><li>Octobre : focus sur les shaders et materials en world-space.</li><li>Novembre - Février : consolidation de la librairie et élargissement du catalogue de shaders.</li></ul></li><li><strong>Plan B (si ça ne fonctionne pas) :</strong> maintien de l&#39;architecture actuelle spécifique à chaque backend. <ul><li>Août : intégration de Slang dans le workflow et migration des shaders GLSL existants vers Slang.</li><li>Septembre : implémentation des shaders world-space directement dans la librairie actuelle, si pas déjà fait.</li><li>Octobre - Février : mêmes travaux de consolidation et d&#39;élargissement du catalogue de shaders que pour le Plan A.</li></ul></li></ul>',20)])])}const m=t(n,[["render",s]]);export{h as __pageData,m as default};
